SELECT o.id, o.user_id, o.order_no, o.amount, o.status, o.pickup_type, o.pickup_no, o.reject_reason, o.create_time, u.nickname AS user_name FROM `order` o LEFT JOIN user u ON o.user_id = u.id
AND o.status = #{status}
AND o.order_no LIKE CONCAT('%', #{orderNo}, '%')
ORDER BY o.create_time DESC LIMIT #{offset}, #{pageSize}

SELECT COUNT(*) FROM `order` o


        AND o.status = #{status}


        AND o.order_no LIKE CONCAT('%', #{orderNo}, '%')

SELECT id, user_id, order_no, amount, status, pickup_type, pickup_no, reject_reason, create_time
FROM `order`
WHERE user_id = #{userId}

    AND status = #{status}

ORDER BY create_time DESC
